        fused_gemm_bn_scale_softmax_kernel<scalar_t><<<grid_dim, block_dim>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.data_ptr<scalar_t>(),
            running_mean.data_ptr<scalar_t>(),
            running_var.data_ptr<scalar_t>(),
            scale.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size, in_features, out_features,
            static_cast<scalar_t>(eps)
        );
    }));

    cudaDeviceSynchronize();

    // Launch online softmax kernel
    int softmax_threads = 256;
    int softmax_blocks = batch_size;
    size_t shared_mem_size = 2 * softmax_threads * sizeof(float);

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "online_softmax", ([&] {
        online_softmax_kernel<scalar_t><<<softmax_blocks, softmax_threads, shared_mem_size>>>(
            output.data_ptr<scalar_t>(),
            batch_size, out_features
        );
    }));

    return output;
}
