fused_operator = load_inline(
    name="fused_gemm_bn_scale_softmax",
    cpp_sources=fused_kernel_cpp_source,
    cuda_sources=fused_kernel_source,
    functions=["fused_gemm_bn_scale_softmax_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)


class ModelNew(nn.Module):
    """
    Optimized model with fused CUDA kernel for Gemm + BatchNorm + Scale + Softmax.
    """
    def __init__(self, in_features, out_features, bn_eps=1e-5, bn_momentum=0.1, scale_shape=(1,)):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.bn_eps = bn_eps
        self.bn_momentum = bn_momentum

        # Store parameters directly
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        self.bias = nn.Parameter(torch.empty(out_features))
        self.scale = nn.Parameter(torch.ones(scale_shape))

        # BatchNorm statistics
        self.register_buffer('running_mean', torch.zeros(out_features))
        self.register_buffer('running_var', torch.ones(out_features))
        self.register_buffer('num_batches_tracked', torch.tensor(0, dtype=torch.long))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
        bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
        nn.init.uniform_(self.bias, -bound, bound)

        # CUDA operator
        self.fused_op = fused_operator

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_features).
        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_features).
        """
        if self.training:
            # In training mode, compute batch statistics and update running stats
            with torch.no_grad():
                # Perform linear transformation
                gemm_output = torch.matmul(x, self.weight.t()) + self.bias

                # Compute batch statistics
                batch_mean = gemm_output.mean(dim=0)
                batch_var = gemm_output.var(dim=0, unbiased=False)

                # Update running statistics
                momentum = self.bn_momentum
                self.running_mean = self.running_mean * (1 - momentum) + batch_mean * momentum
                self.running_var = self.running_var * (1 - momentum) + batch_var * momentum
                self.num_batches_tracked += 1

            # For training, use batch statistics in the fused kernel
            # We need to pass batch_mean and batch_var instead of running stats
            batch_mean = gemm_output.mean(dim=0)
            batch_var = gemm_output.var(dim=0, unbiased=False)

            # Create temporary tensors for batch statistics
            batch_mean_tensor = batch_mean.detach()
            batch_var_tensor = batch_var.detach()

            return self.fused_op.fused_gemm_bn_scale_softmax_cuda(
                x, self.weight, self.bias,
                batch_mean_tensor, batch_var_tensor, self.scale,
                self.bn_eps
            )
        else:
            # In eval mode, use running statistics
            return self.fused_op.fused_gemm_bn_scale_softmax_cuda(
                x, self.weight, self.bias,
                self.running_mean, self.running_var, self.scale,
                self.bn_eps
            )

