#include <cuda_runtime.h>
#include <math.h>

template<typename T>
__global__ void fused_gemm_bn_scale_softmax_kernel(
    const T* input, const T* weight, const T* bias,
    const T* running_mean, const T* running_var, const T* scale,
    T* output, int batch_size, int in_features, int out_features,
    T eps
) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < batch_size && col < out_features) {
        // Gemm operation
        T val = bias[col];
        const T* weight_ptr = weight + col * in_features;
        const T* input_ptr = input + row * in_features;

        #pragma unroll(4)
        for (int k = 0; k < in_features; ++k) {
            val += input_ptr[k] * weight_ptr[k];
        }

        // Batch Normalization
        T mean = running_mean[col];
        T var = running_var[col];
        T normalized = (val - mean) / sqrt(var + eps);

        // Scale
        T scaled = normalized * scale[0];

        // Store for softmax
        output[row * out_features + col] = scaled;
    }
}

template<typename T>
__global__ void online_softmax_kernel(
    T* data, int batch_size, int out_features
) {
    extern __shared__ char shared_mem_char[];
    T* shared_mem = reinterpret_cast<T*>(shared_mem_char);
    T* max_vals = shared_mem;
    T* sum_vals = &shared_mem[blockDim.x];

    int row = blockIdx.x;
    int tid = threadIdx.x;

    // Find max value in the row
    T thread_max = -INFINITY;
    for (int i = tid; i < out_features; i += blockDim.x) {
        T val = data[row * out_features + i];
        thread_max = fmaxf(thread_max, val);
    }

    max_vals[tid] = thread_max;
    __syncthreads();

    // Reduce to find row max
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride - 1) {
            max_vals[tid] = fmaxf(max_vals[tid], max_vals[tid + stride]);
        }
        __syncthreads();
    }

    T row_max = max_vals[0];
    __syncthreads();

    // Compute exp(x - max) and sum
    T thread_sum = T(0);
    for (int i = tid; i < out_features; i += blockDim.x) {
        T val = data[row * out_features + i];
        T exp_val = expf(val - row_max);
        data[row * out_features + i] = exp_val;
        thread_sum += exp_val;
    }

    sum_vals[tid] = thread_sum;
    __syncthreads();

    // Reduce to find row sum
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            sum_vals[tid] += sum_vals[tid + stride];
        }
        __syncthreads();
    }

    T row_sum = sum_vals[0];

    // Normalize by sum
    for (int i = tid; i < out_features; i += blockDim.x) {
        data[row * out_features + i] /= row_sum;
    }
}

